package main

import "fmt"

func apagar(fila []int, sair []int) {
	for i := 0; i < len(fila); i++ {
		apagou := false

		for j := 0; j < len(sair); j++ {
			if fila[i] == sair[j] {
				apagou = true
			}
		}

		if apagou == false {
			fmt.Print(fila[i], " ")
		}
	}
	fmt.Println()
}

func main() {
	var n int
	fmt.Scan(&n)

	fila := make([]int, n)
	for i := 0; i < n; i++ {
		fmt.Scan(&fila[i])
	}

	var m int
	fmt.Scan(&m)

	sair := make([]int, m)
	for i := 0; i < m; i++ {
		fmt.Scan(&sair[i])
	}

	apagar(fila, sair)
}
